<?php
namespace App\Http\Controllers; use App\Models\{KnowledgeMachine,KnowledgeNote}; use Illuminate\Http\{JsonResponse,Request,Response}; use Illuminate\Validation\Rule;
class KnowledgeNoteController extends Controller { public function index(KnowledgeMachine $knowledgeMachine):JsonResponse{return response()->json($knowledgeMachine->notes()->with('media')->orderByDesc('is_pinned')->latest()->get());} public function store(Request $r,KnowledgeMachine $knowledgeMachine):JsonResponse{$this->write($r);$d=$this->valid($r);$d+=['knowledge_machine_id'=>$knowledgeMachine->id,'created_by'=>$r->user()->id,'updated_by'=>$r->user()->id];return response()->json(KnowledgeNote::create($d),201);} public function update(Request $r,KnowledgeNote $knowledgeNote):JsonResponse{$this->write($r);$d=$this->valid($r,true);$d['updated_by']=$r->user()->id;$knowledgeNote->update($d);return response()->json($knowledgeNote->fresh());} public function destroy(Request $r,KnowledgeNote $knowledgeNote):Response{$this->write($r);$knowledgeNote->delete();return response()->noContent();} private function write(Request $r):void{abort_unless(in_array($r->user()->role,['admin','technician']),403);} private function valid(Request $r,bool $p=false):array{$x=$p?'sometimes|required':'required';return $r->validate(['title'=>[$x,'string','max:255'],'note_type'=>[$x,Rule::in(['general','troubleshooting','maintenance','procedure','parts','warning'])],'content'=>[$x,'string'],'is_pinned'=>['sometimes','boolean']]);}}
